const raw = $json ?? {};
const userInput = typeof raw.userInput === 'string' && raw.userInput.trim().length > 0
  ? raw.userInput.trim()
  : '';
if (!userInput) {
  throw new Error('AISMR workflow requires a non-empty userInput.');
}
const chatId = typeof raw.chatId === 'string' && raw.chatId.trim().length > 0
  ? raw.chatId.trim()
  : null;
const project = {
  id: 'a372acc6-5b6a-46c5-835d-6e9859d5055c',
  slug: 'aismr',
  name: 'AISMR'
};
const requestId = `aismr-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
return {
  json: {
    userInput,
    chatId,
    project,
    requestId,
    timestamps: {
      receivedAt: new Date().toISOString()
    }
  }
};

const request = $('Normalize Request').item.json;
const runResponse = $('Create Run').item.json;
const run = runResponse?.data?.run ?? runResponse?.run ?? runResponse;
if (!run || !run.id) {
  throw new Error('Unable to determine run id from Create Run response.');
}
const outputSchema = JSON.stringify({
  type: 'object',
  properties: {
    userIdea: {
      type: 'string',
      description: 'Normalized base object (lowercase singular) applied to every idea.'
    },
    ideas: {
      type: 'array',
      minItems: 12,
      maxItems: 12,
      items: {
        type: 'object',
        properties: {
          idea: {
            type: 'string',
            description: 'Title Case descriptor + singular object (two words, descriptor is one word).'
          },
          vibe: {
            type: 'string',
            description: '2-4 sentence explanation covering emotion, hook, texture, feasibility, replay value, and environment potential.'
          }
        },
        required: ['idea', 'vibe'],
        additionalProperties: false
      }
    }
  },
  required: ['userIdea', 'ideas'],
  additionalProperties: false
});
return {
  json: {
    persona: 'ideagenerator',
    project: request.project.slug,
    projectId: request.project.id,
    chatInput: request.userInput,
    chatId: request.chatId ?? null,
    runId: run.id,
    run,
    outputSchema,
    request
  }
};

const agentOutput = $json ?? {};
const context = $('Prepare Idea Job').item.json;
const runId = context.runId;
const projectId = context.projectId;
let payload = agentOutput.structuredContent
  ?? agentOutput.result?.structuredContent
  ?? agentOutput.result?.output
  ?? agentOutput.output
  ?? agentOutput.result
  ?? agentOutput.data?.structuredContent
  ?? agentOutput.data
  ?? null;
if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (error) {
    throw new Error(`Unable to parse idea generator payload: ${error.message}`);
  }
}
if (!payload || typeof payload !== 'object') {
  throw new Error('Idea generator returned an unexpected response shape.');
}
const ideas = Array.isArray(payload.ideas) ? payload.ideas : [];
if (ideas.length === 0) {
  throw new Error('Idea generator returned zero ideas.');
}
const normalizedIdeas = ideas.map((entry, index) => {
  if (!entry || typeof entry !== 'object') {
    throw new Error(`Idea entry at index ${index} is invalid.`);
  }
  const idea = typeof entry.idea === 'string' ? entry.idea.trim() : '';
  const vibe = typeof entry.vibe === 'string' ? entry.vibe.trim() : '';
  if (!idea || !vibe) {
    throw new Error(`Idea entry at index ${index} is missing required fields.`);
  }
  return {
    idea,
    vibe,
    metadata: {
      original: entry
    }
  };
});
return {
  json: {
    runId,
    projectId,
    userIdea: typeof payload.userIdea === 'string' ? payload.userIdea : null,
    ideas: normalizedIdeas,
    agentOutput
  }
};

const { ideas, runId, projectId, userIdea } = $json;
return ideas.map((entry, index) => ({
  json: {
    runId,
    projectId,
    userIdea,
    idea: entry.idea,
    vibe: entry.vibe,
    rank: index + 1
  }
}));

const ideaData = $('Extract Ideas').item.json;
const videoItems = $items('Create Idea Records', 0, -1).map((item) => item.json ?? {});
return {
  json: {
    runId: ideaData.runId,
    projectId: ideaData.projectId,
    userIdea: ideaData.userIdea,
    ideas: ideaData.ideas,
    videoRecords: videoItems
  }
};

const ideas = Array.isArray($json.ideas) ? $json.ideas : [];
const userIdea = $json.userIdea || 'your brief';
const runId = $json.runId;
const projectId = $json.projectId;
const topIdeas = ideas.slice(0, 3);
const bullets = topIdeas.map((entry, index) => `  ${index + 1}. ${entry.idea}: ${entry.vibe}`);
const summaryLines = [`Generated ${ideas.length} AISMR-ready concepts for "${userIdea}".`];
if (bullets.length) {
  summaryLines.push(`Top concepts:
${bullets.join('\n')}`);
} else {
  summaryLines.push('No highlightable concepts were produced.');
}
const summary = summaryLines.join('\n\n');
return {
  json: {
    responseText: summary,
    runId,
    projectId,
    userIdea,
    ideaCount: ideas.length,
    ideas
  }
};
